// Data classes for parsed deep link results
sealed class DeepLinkResult {
    data class Profile(val userId: String) : DeepLinkResult()
    data class PaymentConfirm(val transactionId: String?, val amount: String?) : DeepLinkResult()
    data class Error(val message: String) : DeepLinkResult()
