// Allowlisted routes
object DeepLinkConfig {
    val SCHEME = "myapp"

    // Allowlisted hosts
    val ALLOWED_HOSTS = setOf(
        "profile",
        "payment"
    )

    // Allowlisted paths per host
    val ALLOWED_PATHS: Map<String, Set<String>> = mapOf(
        "profile" to setOf(""), // myapp://profile/{id}
        "payment" to setOf("/confirm") // myapp://payment/confirm
    )

    // Validation constraints
    const val MAX_USER_ID_LENGTH = 20
    const val MAX_PARAM_LENGTH = 256
    val USER_ID_PATTERN = Regex("^[a-zA-Z0-9_-]+$")
    val TRANSACTION_ID_PATTERN = Regex("^[a-zA-Z0-9_-]+$")
    val AMOUNT_PATTERN = Regex("^[0-9]+(\\.[0-9]{1,2})?$")
}

// Validator for deep link parameters
object DeepLinkValidator {

    fun isValidScheme(uri: Uri): Boolean {
        return uri.scheme == DeepLinkConfig.SCHEME
    }

    fun isAllowedHost(host: String?): Boolean {
        return host != null && host in DeepLinkConfig.ALLOWED_HOSTS
    }

    fun isAllowedPath(host: String?, path: String?): Boolean {
        if (host == null) return false
        val allowedPaths = DeepLinkConfig.ALLOWED_PATHS[host] ?: return false
        val normalizedPath = path ?: ""
        return normalizedPath in allowedPaths
    }

    fun sanitizeParam(param: String?): String? {
        if (param == null) return null
        if (param.length > DeepLinkConfig.MAX_PARAM_LENGTH) return null
        // Strip any potentially dangerous characters
        val sanitized = param.trim()
        if (sanitized.isEmpty()) return null
        return sanitized
    }

    fun isValidUserId(userId: String?): Boolean {
        if (userId == null) return false
        if (userId.length > DeepLinkConfig.MAX_USER_ID_LENGTH) return false
        return DeepLinkConfig.USER_ID_PATTERN.matches(userId)
    }

    fun isValidTransactionId(transactionId: String?): Boolean {
        if (transactionId == null) return true // optional param
        if (transactionId.length > DeepLinkConfig.MAX_PARAM_LENGTH) return false
        return DeepLinkConfig.TRANSACTION_ID_PATTERN.matches(transactionId)
    }

    fun isValidAmount(amount: String?): Boolean {
        if (amount == null) return true // optional param
        if (amount.length > 20) return false
        return DeepLinkConfig.AMOUNT_PATTERN.matches(amount)
    }

    fun hasNoInjectionAttempt(value: String?): Boolean {
        if (value == null) return true
        val dangerous = listOf("<", ">", "javascript:", "data:", "'", "\"", ";", "--", "/*", "*/")
        return dangerous.none { value.lowercase().contains(it) }
    }
}

// Deep link parser
object DeepLinkParser {

    private const val TAG = "DeepLinkParser"

    fun parse(uri: Uri?): DeepLinkResult {
        if (uri == null) {
            return DeepLinkResult.Error("Null URI")
        }

        Log.d(TAG, "Parsing deep link: $uri")

        // Validate scheme
        if (!DeepLinkValidator.isValidScheme(uri)) {
            Log.w(TAG, "Invalid scheme: ${uri.scheme}")
            return DeepLinkResult.Error("Invalid scheme")
        }

        val host = uri.host

        // Validate host against allowlist
        if (!DeepLinkValidator.isAllowedHost(host)) {
            Log.w(TAG, "Host not in allowlist: $host")
            return DeepLinkResult.Error("Route not allowed")
        }

        return when (host) {
            "profile" -> parseProfile(uri)
            "payment" -> parsePayment(uri)
            else -> {
                Log.w(TAG, "Unhandled host: $host")
                DeepLinkResult.Error("Unknown route")
            }
        }
    }

    // Parse myapp://profile/{userId}
    private fun parseProfile(uri: Uri): DeepLinkResult {
        val pathSegments = uri.pathSegments

        if (pathSegments.isEmpty()) {
            return DeepLinkResult.Error("Missing profile ID")
        }

        val rawUserId = pathSegments[0]
        val userId = DeepLinkValidator.sanitizeParam(rawUserId)

        if (!DeepLinkValidator.isValidUserId(userId)) {
            Log.w(TAG, "Invalid user ID format")
            return DeepLinkResult.Error("Invalid profile ID")
        }

        if (!DeepLinkValidator.hasNoInjectionAttempt(userId)) {
            Log.w(TAG, "Potential injection attempt in user ID")
            return DeepLinkResult.Error("Invalid profile ID")
        }

        return DeepLinkResult.Profile(userId!!)
    }

    // Parse myapp://payment/confirm?transaction_id=xxx&amount=yyy
    private fun parsePayment(uri: Uri): DeepLinkResult {
        val path = uri.path

        if (!DeepLinkValidator.isAllowedPath("payment", path)) {
            Log.w(TAG, "Path not allowed for payment: $path")
            return DeepLinkResult.Error("Invalid payment route")
        }

        val rawTransactionId = uri.getQueryParameter("transaction_id")
        val rawAmount = uri.getQueryParameter("amount")

        val transactionId = DeepLinkValidator.sanitizeParam(rawTransactionId)
        val amount = DeepLinkValidator.sanitizeParam(rawAmount)

        if (!DeepLinkValidator.isValidTransactionId(transactionId)) {
            Log.w(TAG, "Invalid transaction ID format")
            return DeepLinkResult.Error("Invalid transaction ID")
        }

        if (!DeepLinkValidator.isValidAmount(amount)) {
            Log.w(TAG, "Invalid amount format")
            return DeepLinkResult.Error("Invalid amount")
        }

        if (!DeepLinkValidator.hasNoInjectionAttempt(transactionId) ||
            !DeepLinkValidator.hasNoInjectionAttempt(amount)
        ) {
            Log.w(TAG, "Potential injection attempt in payment params")
            return DeepLinkResult.Error("Invalid payment parameters")
        }

        return DeepLinkResult.PaymentConfirm(transactionId, amount)
    }
}

// Navigator that routes to appropriate activities
object DeepLinkNavigator {

    private const val TAG = "DeepLinkNavigator"

    fun navigate(context: Context, result: DeepLinkResult): Boolean {
        return when (result) {
            is DeepLinkResult.Profile -> {
                navigateToProfile(context, result.userId)
                true
            }
            is DeepLinkResult.PaymentConfirm -> {
                navigateToPaymentConfirm(context, result.transactionId, result.amount)
                true
            }
            is DeepLinkResult.Error -> {
                Log.w(TAG, "Deep link error: ${result.message}")
                navigateToMain(context)
                false
            }
        }
    }

    private fun navigateToProfile(context: Context, userId: String) {
        Log.d(TAG, "Navigating to profile: $userId")
        val intent = Intent(context, ProfileActivity::class.java).apply {
            putExtra(ProfileActivity.EXTRA_USER_ID, userId)
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        }
        context.startActivity(intent)
    }

    private fun navigateToPaymentConfirm(context: Context, transactionId: String?, amount: String?) {
        Log.d(TAG, "Navigating to payment confirm: txn=$transactionId, amount=$amount")
        val intent = Intent(context, PaymentConfirmActivity::class.java).apply {
            transactionId?.let { putExtra(PaymentConfirmActivity.EXTRA_TRANSACTION_ID, it) }
            amount?.let { putExtra(PaymentConfirmActivity.EXTRA_AMOUNT, it) }
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        }
        context.startActivity(intent)
    }

    private fun navigateToMain(context: Context) {
        Log.d(TAG, "Navigating to main (fallback)")
        val intent = Intent(context, MainActivity::class.java).apply {
            addFlags(Intent.FLAG_ACTIVITY_NEW_TASK or Intent.FLAG_ACTIVITY_CLEAR_TOP)
        }
        context.startActivity(intent)
    }
}

