// Utility to create deep link URIs programmatically (for testing or push notifications)
object DeepLinkBuilder {

    fun buildProfileLink(userId: String): Uri? {
        if (!DeepLinkValidator.isValidUserId(userId)) return null
        return Uri.Builder()
            .scheme(DeepLinkConfig.SCHEME)
            .authority("profile")
            .appendPath(userId)
            .build()
    }

    fun buildPaymentConfirmLink(transactionId: String? = null, amount: String? = null): Uri? {
        if (!DeepLinkValidator.isValidTransactionId(transactionId)) return null
        if (!DeepLinkValidator.isValidAmount(amount)) return null

        val builder = Uri.Builder()
            .scheme(DeepLinkConfig.SCHEME)
            .authority("payment")
            .appendPath("confirm")

        transactionId?.let { builder.appendQueryParameter("transaction_id", it) }
        amount?.let { builder.appendQueryParameter("amount", it) }

        return builder.build()
    }
}